1	export function nextGeneration(cells: [number, number][]): [number, number][] {
2	  const isAlive = (x: number, y: number): boolean =>
3	    cells.some(([cx, cy]) => cx === x && cy === y);
4	
5	  const neighborOffsets: [number, number][] = [
6	    [-1, -1], [-1, 0], [-1, 1],
7	    [0, -1], [0, 1],
8	    [1, -1], [1, 0], [1, 1],
9	  ];
10	
11	  const countNeighbors = (x: number, y: number): number =>
12	    neighborOffsets.filter(([dx, dy]) => isAlive(x + dx, y + dy)).length;
13	
14	  return cells.filter(([x, y]) => {
15	    const neighbors = countNeighbors(x, y);
16	    return neighbors === 2 || neighbors === 3;
17	  });
18	}
